// Pocket Watch Movement — an open-face skeleton pocket watch with an EXPOSED
// brass gear train laid bare across the dial.
//
// Reference: antique open-face / skeleton pocket watches (e.g. brass full-plate
// movements and "squelette" skeletonized watches) — a round case with a stepped
// bezel, a fluted crown + bow loop at 12 o'clock, and a visible train of
// meshing spur gears (mainspring barrel, center wheel, third/fourth wheels,
// escape wheel) plus a spoked balance wheel, accented with red ruby jewels.
//
// Showcases BOSL2 `spur_gear()` + `gear_dist()` — true involute teeth that
// manifold can't easily produce — for the whole exposed train.
//
// COLOR: every paintable piece is a top-level `label("name") <expr>;` statement
// so each region self-colors via paintByLabel. SCAD labels survive ONLY when
// each labeled statement maps 1:1 to a lazy-union AMF object, so EVERY loop is
// UNROLLED into explicit top-level statements (a `for(...) label(...)` emits N
// objects from one statement, the count mismatches, and ALL labels are dropped).
// Helper modules are fine: one invocation = one object.

include <BOSL2/std.scad>
include <BOSL2/gears.scad>

$fa = 4;
$fs = 0.5;

// ---------------------------------------------------------------------------
// Parameters
// ---------------------------------------------------------------------------
circ_pitch  = 2.8;     // circular pitch shared by the whole gear train
gear_thk    = 6;       // gear face width (tall so the wheels pop above the dial)

case_r      = 62;      // outer case radius
case_thk    = 12;      // case body thickness (the back plate the train rides on)
bezel_h     = 6;       // raised bezel ring height
plate_z     = case_thk; // top surface of the back plate (train sits on this)

// Tooth counts for the train (decreasing size from barrel to escape wheel).
barrel_teeth = 40;     // big mainspring barrel
center_teeth = 26;     // center wheel
third_teeth  = 20;     // third wheel
fourth_teeth = 15;     // fourth wheel
escape_teeth = 11;     // escape wheel (smallest)

// Pitch radii (for layout) — r = circ_pitch * teeth / (2*PI).
function pr(t) = circ_pitch * t / (2 * PI);

// Center-to-center distances for each meshing pair.
d_bc = gear_dist(circ_pitch=circ_pitch, teeth1=barrel_teeth, teeth2=center_teeth);
d_ct = gear_dist(circ_pitch=circ_pitch, teeth1=center_teeth, teeth2=third_teeth);
d_tf = gear_dist(circ_pitch=circ_pitch, teeth1=third_teeth,  teeth2=fourth_teeth);
d_fe = gear_dist(circ_pitch=circ_pitch, teeth1=fourth_teeth, teeth2=escape_teeth);

// ---------------------------------------------------------------------------
// Gear centre positions — the barrel sits lower-left; the train arcs up and to
// the right across the dial toward the escapement, staying inside the bezel
// window so every wheel reads distinctly and meshes with its neighbour.
// ---------------------------------------------------------------------------
p_barrel = [-15, -13];
ang_bc   = 40;   // heading from barrel to center wheel
p_center = [p_barrel[0] + d_bc * cos(ang_bc), p_barrel[1] + d_bc * sin(ang_bc)];
ang_ct   = 2;
p_third  = [p_center[0] + d_ct * cos(ang_ct), p_center[1] + d_ct * sin(ang_ct)];
ang_tf   = 68;
p_fourth = [p_third[0] + d_tf * cos(ang_tf), p_third[1] + d_tf * sin(ang_tf)];
ang_fe   = 140;
p_escape = [p_fourth[0] + d_fe * cos(ang_fe), p_fourth[1] + d_fe * sin(ang_fe)];

// Balance wheel sits in the open lower-right area, clear of the train.
p_balance = [22, -24];
balance_r = 16;

dial_z = plate_z;                       // open dial floor = top of the case body
gear_z = dial_z + gear_thk / 2 - 1.0;   // gears sit on the dial, biting 1mm in

// ---------------------------------------------------------------------------
// Helper modules (geometry only — never labeled inside; labels are top-level).
// ---------------------------------------------------------------------------

// One spur gear standing on the plate at planar position p, with a hub.
module wheel(p, teeth, spin=0, hub=true) {
  translate([p[0], p[1], gear_z]) {
    spur_gear(circ_pitch=circ_pitch, teeth=teeth, thickness=gear_thk,
              shaft_diam=0, gear_spin=spin);
    if (hub)
      up(gear_thk / 2 - 0.5)
        cyl(h=2.4, d=max(5, pr(teeth) * 0.45), rounding2=0.8, anchor=BOTTOM);
  }
}

// The mainspring barrel: a tall toothed drum with a low cap (the spring cover).
module barrel(p, teeth) {
  translate([p[0], p[1], gear_z]) {
    spur_gear(circ_pitch=circ_pitch, teeth=teeth, thickness=gear_thk);
    up(gear_thk / 2 - 0.5)
      cyl(h=3.2, r=pr(teeth) * 0.78, rounding2=1.2, anchor=BOTTOM);
  }
}

// A ruby jewel — a small red disc capping a pivot, with a chamfered bevel.
module jewel(p, z, d=4) {
  translate([p[0], p[1], z])
    cyl(h=1.6, d=d, chamfer2=0.5, anchor=BOTTOM);
}

// A blued-steel screw head at planar position p on the plate.
module screw(p, z) {
  translate([p[0], p[1], z])
    cyl(h=2.2, d=5, $fn=20, chamfer2=0.6, anchor=BOTTOM);
}

// A bridge bar — a slim rounded brass plate spanning two pivot points, raised
// above the train (the cocks/bridges that hold the wheels in a real movement).
module bridge(a, b, w=7, h=3, z=0) {
  mid = [(a[0]+b[0])/2, (a[1]+b[1])/2];
  len = norm([b[0]-a[0], b[1]-a[1]]) + 12;
  ang = atan2(b[1]-a[1], b[0]-a[0]);
  translate([mid[0], mid[1], z])
    rotate([0, 0, ang])
      cuboid([len, w, h], rounding=w/2, edges="Z", anchor=BOTTOM);
}

// ---------------------------------------------------------------------------
// CASE — round body whose top forms the open dial, ringed by a raised stepped
// bezel. The dial stays a flat, low floor so the exposed train stands proud of
// it (skeleton look). ONE statement.
// ---------------------------------------------------------------------------
bezel_ir = case_r - 9;   // inner radius of the bezel window (the open dial)
label("case")
  union() {
    // Body: solid disc, top at z = plate_z forms the dial floor.
    cyl(h=case_thk, r=case_r, rounding1=2.5, anchor=BOTTOM);
    // Raised bezel ring framing the open dial window.
    up(plate_z - 1)
      tube(h=bezel_h + 1, or=case_r, ir=bezel_ir, $fn=160);
    // Outer beaded lip on top of the bezel.
    up(plate_z + bezel_h - 0.6)
      tube(h=1.8, or=case_r, ir=case_r - 4, rounding1=0.8, $fn=160);
  }

// Open dial floor inside the bezel — a thin contrasting plate the train rides
// on. Kept low so the gears clearly stand above it.
label("dial")
  up(plate_z - 0.2) cyl(h=1.0, r=bezel_ir + 1, anchor=BOTTOM);

// ---------------------------------------------------------------------------
// CROWN + BOW — winding knob and loop at 12 o'clock (top, +Y).
// ---------------------------------------------------------------------------
crown_z = case_thk / 2;   // crown axis at the case body mid-height

// Pendant neck connecting the case to the crown.
label("pendant")
  translate([0, case_r - 2, crown_z])
    cyl(h=8, d=13, rounding=1, anchor=BOTTOM, orient=BACK);

// Fluted winding crown (a knurled knob).
label("crown")
  translate([0, case_r + 9, crown_z])
    cyl(h=10, d=16, texture="diamonds", tex_size=[3,3], tex_depth=0.8,
        rounding=1.6, anchor=BOTTOM, orient=BACK, $fn=48);

// Bow — the suspension loop above the crown (a torus standing upright).
label("bow")
  translate([0, case_r + 21, crown_z])
    rotate([90, 0, 0])
      torus(r_maj=11, r_min=2.8, $fn=48);

// ---------------------------------------------------------------------------
// GEAR TRAIN — mainspring barrel + four meshing wheels (each its own
// statement; tooth phasing offset so adjacent gears interlock visually).
// ---------------------------------------------------------------------------
label("barrel")       barrel(p_barrel, barrel_teeth);
label("center_wheel") wheel(p_center, center_teeth, spin=180/center_teeth);
label("third_wheel")  wheel(p_third,  third_teeth,  spin=180/third_teeth);
label("fourth_wheel") wheel(p_fourth, fourth_teeth);
label("escape_wheel") wheel(p_escape, escape_teeth, spin=180/escape_teeth, hub=false);

// ---------------------------------------------------------------------------
// BALANCE WHEEL — a spoked rim that oscillates (upper-right open area). Built
// as one helper invocation = one object so its label survives.
// ---------------------------------------------------------------------------
module balance(p, r) {
  translate([p[0], p[1], gear_z]) {
    tube(h=gear_thk, or=r, ir=r - 3.2, $fn=72);          // rim
    // Four spokes across the rim.
    for (a = [0, 90])
      rotate([0, 0, a]) cuboid([2*r - 2, 2.4, gear_thk], anchor=CENTER);
    cyl(h=gear_thk + 1.5, d=6, anchor=CENTER);            // staff/hub
  }
}
label("balance") balance(p_balance, balance_r);

// Balance staff cap + its jewel.
label("balance_cap")
  translate([p_balance[0], p_balance[1], gear_z + gear_thk/2 + 0.6])
    cyl(h=2, d=8, rounding2=0.8, anchor=BOTTOM);

// ---------------------------------------------------------------------------
// BRIDGES — slim brass bars over the train (purely visual cocks/bridges).
// ---------------------------------------------------------------------------
brz = gear_z + gear_thk/2 + 1.0;
// Escapement bridge over the fourth + escape wheels.
label("bridges") bridge(p_fourth, p_escape,  w=4.5, h=2.8, z=brz);
// Balance cock: an arm from the case rim out to the balance staff.
label("bridges") bridge([p_balance[0]+10, p_balance[1]-14], p_balance, w=5, h=2.8, z=brz);

// ---------------------------------------------------------------------------
// JEWELS — red ruby pivot stones capping each wheel arbor (unrolled).
// ---------------------------------------------------------------------------
jz = gear_z + gear_thk/2 + 0.4;
label("jewels") jewel(p_center,  jz + 1.6, 4);
label("jewels") jewel(p_third,   jz + 1.6, 4);
label("jewels") jewel(p_fourth,  jz + 1.6, 4);
label("jewels") jewel(p_escape,  jz + 1.6, 3.5);
label("jewels") jewel(p_barrel,  gear_z + gear_thk/2 + 2.4, 4.5);
label("jewels") jewel(p_balance, gear_z + gear_thk/2 + 2.4, 4.5);

// ---------------------------------------------------------------------------
// SCREWS — blued steel screws around the bezel + on the bridges (unrolled).
// ---------------------------------------------------------------------------
sz = plate_z + bezel_h - 0.8;   // sit on the bezel rim, biting in to fuse
sr = (case_r + bezel_ir) / 2;   // mid-bezel radius
label("screws") screw([ sr,  0], sz);
label("screws") screw([-sr,  0], sz);
label("screws") screw([0,  -sr], sz);
label("screws") screw([ sr*cos(45),   sr*sin(45)],  sz);
label("screws") screw([ sr*cos(135),  sr*sin(135)], sz);
label("screws") screw([ sr*cos(225),  sr*sin(225)], sz);
label("screws") screw([ sr*cos(315),  sr*sin(315)], sz);

